#### `frontend/src/auth/keycloak.ts`
```typescript
import Keycloak from 'keycloak-js';

const keycloakConfig = {
  url: import.meta.env.VITE_KEYCLOAK_URL || 'http://localhost:8080',
  realm: import.meta.env.VITE_KEYCLOAK_REALM || 'ai-maturity',
  clientId: import.meta.env.VITE_KEYCLOAK_CLIENT_ID || 'frontend-spa',
};

export const keycloak = new Keycloak(keycloakConfig);

export type UserRole =
  | 'super_admin'
  | 'facilitator'
  | 'analyst'
  | 'sales'
  | 'client'
  | 'auditor';

export const getUserRoles = (): UserRole[] => {
  const tokenParsed = keycloak.tokenParsed as any;
  if (!tokenParsed) return [];

  const realmRoles: string[] = tokenParsed.realm_access?.roles || [];
  const clientRoles: string[] =
    tokenParsed.resource_access?.[keycloakConfig.clientId]?.roles || [];

  const allRoles = [...realmRoles, ...clientRoles];
  const validRoles: UserRole[] = [
    'super_admin',
    'facilitator',
    'analyst',
    'sales',
    'client',
    'auditor',
  ];

  return allRoles.filter((r): r is UserRole => validRoles.includes(r as UserRole));
};

export const hasRole = (role: UserRole): boolean => {
  const roles = getUserRoles();
  return roles.includes('super_admin') || roles.includes(role);
};

export const hasAnyRole = (roles: UserRole[]): boolean => {
  return roles.some((role) => hasRole(role));
};

export const initializeKeycloak = async (): Promise<boolean> => {
  try {
    const authenticated = await keycloak.init({
      onLoad: 'check-sso',
      silentCheckSsoRedirectUri:
        window.location.origin + '/silent-check-sso.html',
      pkceMethod: 'S256',
      checkLoginIframe: false,
    });

    if (authenticated) {
      // Token refresh
      setInterval(async () => {
        try {
          await keycloak.updateToken(30);
        } catch {
          keycloak.login();
        }
      }, 60000);
    }

    return authenticated;
  } catch (error) {
    console.error('Keycloak init failed:', error);
    return false;
  }
};
```

#### `frontend/src/auth/KeycloakProvider.tsx`
```tsx
import { createContext, useContext, useEffect, useState, ReactNode } from 'react';
import { keycloak, initializeKeycloak, getUserRoles, UserRole } from './keycloak';

interface AuthContextType {
  isAuthenticated: boolean;
  isLoading: boolean;
  user: {
    id: string;
    email: string;
    name: string;
    roles: UserRole[];
  } | null;
  login: () => void;
  logout: () => void;
  getToken: () => string | undefined;
  hasRole: (role: UserRole) => boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const KeycloakProvider = ({ children }: { children: ReactNode }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState<AuthContextType['user']>(null);

  useEffect(() => {
    const init = async () => {
      const authenticated = await initializeKeycloak();
      setIsAuthenticated(authenticated);

      if (authenticated) {
        const tokenParsed = keycloak.tokenParsed as any;
        setUser({
          id: tokenParsed?.sub || '',
          email: tokenParsed?.email || tokenParsed?.preferred_username || '',
          name: `${tokenParsed?.given_name || ''} ${tokenParsed?.family_name || ''}`.trim(),
          roles: getUserRoles(),
        });
      }

      setIsLoading(false);
    };

    init();
  }, []);

  const login = () => keycloak.login();
  const logout = () => keycloak.logout();
  const getToken = () => keycloak.token;

  const hasRole = (role: UserRole): boolean => {
    if (!user) return false;
    return user.roles.includes('super_admin') || user.roles.includes(role);
  };

  return (
    <AuthContext.Provider
      value={{
        isAuthenticated,
        isLoading,
        user,
        login,
        logout,
        getToken,
        hasRole,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within KeycloakProvider');
  }
  return context;
};
```

