        <Badge variant={getMaturityBadgeVariant(a.calculated_indices?.maturity_level || '')}>
          {a.calculated_indices?.maturity_level}
        </Badge>
      ),
    },
    {
      key: 'status',
      header: 'Статус',
      render: (a: Audit) => (
        <Badge
          variant={
            a.status === 'completed'
              ? 'success'
              : a.status === 'archived'
              ? 'neutral'
              : 'warning'
          }
        >
          {a.status}
        </Badge>
      ),
    },
  ];

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
