```bash
#!/bin/bash
# Quick start script for AI Maturity Platform

set -e

echo "🚀 Starting AI Maturity Platform..."
echo "===================================="

# Check Docker
if ! command -v docker &> /dev/null; then
    echo "❌ Docker is not installed. Please install Docker first."
    exit 1
fi

if ! command -v docker-compose &> /dev/null; then
    echo "❌ Docker Compose is not installed. Please install Docker Compose first."
    exit 1
fi

# Create data directories
echo "📁 Creating data directories..."
mkdir -p data_storage/raw_audits
mkdir -p data_storage/aggregated
mkdir -p data_storage/reports
mkdir -p data_storage/exports
mkdir -p data_storage/logs

# Copy environment file
if [ ! -f .env ]; then
    echo "📝 Creating .env file from template..."
    cp .env.example .env
fi

# Start infrastructure
echo "🐳 Starting Docker containers..."
cd infrastructure
docker-compose up -d

# Wait for services
echo "⏳ Waiting for services to start..."
sleep 10

# Check services
echo "✅ Checking services..."
curl -f http://localhost:8000/health > /dev/null 2>&1 && echo "  ✓ Backend is running" || echo "  ✗ Backend failed to start"
curl -f http://localhost:3000 > /dev/null 2>&1 && echo "  ✓ Frontend is running" || echo "  ✗ Frontend failed to start"
curl -f http://localhost:9001 > /dev/null 2>&1 && echo "  ✓ MinIO Console is running" || echo "  ✗ MinIO failed to start"
curl -f http://localhost:8025 > /dev/null 2>&1 && echo "  ✓ MailHog is running" || echo "  ✗ MailHog failed to start"
curl -f http://localhost:8080 > /dev/null 2>&1 && echo "  ✓ Keycloak is running" || echo "  ✗ Keycloak failed to start"
curl -f http://localhost:3001 > /dev/null 2>&1 && echo "  ✓ Baserow is running" || echo "  ✗ Baserow failed to start"

echo ""
echo "🎉 Platform is ready!"
echo ""
echo "📍 Access points:"
echo "  • Frontend:     http://localhost:3000"
echo "  • Backend API:  http://localhost:8000/docs"
echo "  • MinIO:        http://localhost:9001 (minioadmin/minioadmin)"
echo "  • MailHog:      http://localhost:8025"
echo "  • Keycloak:     http://localhost:8080 (admin/admin)"
echo "  • Baserow:      http://localhost:3001"
echo ""
echo "📊 Logs: docker-compose -f infrastructure/docker-compose.yml logs -f"
echo "🛑 Stop: docker-compose -f infrastructure/docker-compose.yml down"
