#### `reset.sh` (корневой)
```bash
#!/bin/bash
# Reset all data and restart

echo "⚠️  This will delete all data. Are you sure? (y/N)"
read -r response
if [[ "$response" =~ ^([yY][eE][sS]|[yY])$ ]]; then
    echo "🗑️  Stopping services..."
    cd infrastructure
    docker-compose down -v

    echo "🧹 Cleaning data..."
    cd ..
    rm -rf data_storage/*
    mkdir -p data_storage/raw_audits
    mkdir -p data_storage/aggregated
    mkdir -p data_storage/reports
    mkdir -p data_storage/exports
    mkdir -p data_storage/logs

    echo "🚀 Restarting..."
    ./start.sh
else
    echo "❌ Cancelled."
fi
